let message="",messageTone:UiTone="neutral",draft=loadActiveDraft(),preview:Row|null=null,previewSignature="",previewAt=0,loading="",category="All",brandFilter="All",historyFilter="All",searchTimer=0,confirmation:Row|null=null;
let draftStore:SalesDraft[]|null=null,itemIndex=new Map<string,Row>(),itemSearchSequence=0,customerSearchSequence=0,lastItemSearch="",customerQuery="",itemQuery="",reorderCandidates:Row[]=readRows(reorderCacheKey),assortment:Row|null=readCachedAssortment(draft.customer),assortmentOnly=false,deliveryLocations:Row[]=readCachedDeliveryLocations(draft.customer);
