function confirmationText(){if(!confirmation)return "";const pending=text(confirmation,"approval_status")==="Pending";return `Sales Order ${text(confirmation,"sales_order")} · ${text(confirmation,"customer_name","customer")} · ${Number(confirmation.item_count)||0} items · ${formatMoney(confirmation.grand_total,text(confirmation,"currency")||currency())} · ${pending?"Discount approval pending":"Draft in ERPNext"}`}
function confirmationPanel(){if(!confirmation)return "";const pending=text(confirmation,"approval_status")==="Pending";return `<section class="order-confirmation" role="status" aria-label="Sales Order created"><button class="confirmation-close" data-confirmation-close aria-label="Close confirmation">×</button><span class="confirmation-check">${pending?"!":"✓"}</span><div class="confirmation-copy"><p class="eyebrow">${pending?"Manager decision required":"Order created in ERPNext"}</p><h2>${esc(text(confirmation,"sales_order"))}</h2><strong>${esc(text(confirmation,"customer_name","customer"))}</strong><p>${Number(confirmation.item_count)||0} items · ${formatMoney(confirmation.grand_total,text(confirmation,"currency")||currency())}</p><span class="draft-notice">${pending?"Discount approval pending · submission blocked":"Draft · awaiting ERPNext submission"}</span></div><div class="confirmation-actions"><button data-confirmation-share>Share</button><button data-confirmation-copy>Copy number</button><button class="primary" data-confirmation-view>View order</button></div></section>`}
async function copyConfirmation(){if(!confirmation)return;const value=text(confirmation,"sales_order");if(!navigator.clipboard){notice("Clipboard is unavailable on this device.","warning");confirmation=null;return render(screen)}try{await navigator.clipboard.writeText(value);notice(`${value} copied to clipboard.`,"success");confirmation=null}catch{notice("The order number could not be copied.","warning")}render(screen)}
async function shareConfirmation(){if(!confirmation)return;const value=confirmationText();try{if(navigator.share){await navigator.share({title:`Sales Order ${text(confirmation,"sales_order")}`,text:value})}else if(navigator.clipboard){await navigator.clipboard.writeText(value);notice("Order summary copied because native sharing is unavailable.","success")}else{notice("Native sharing is unavailable on this device.","warning")}confirmation=null;render(screen)}catch(error){if((error as DOMException).name!=="AbortError")notice("The order summary could not be shared.","warning");render(screen)}}
function reviewView(){
  const total=estimate(),tax=Number(preview?.total_taxes_and_charges||preview?.taxes||0),grand=Number(preview?.grand_total||total+tax);
  const outstanding=Number(customer?.outstanding_balance||0),limit=Number(customer?.credit_limit||0),creditWarning=Boolean(preview?.credit_warning)||(limit>0&&outstanding+grand>limit);
  return `<section class="page review-page"><div class="page-title"><div><button class="back-button" data-screen="order">‹ Items</button><p class="eyebrow">${editingOrder?`Editing ${esc(editingOrder)}`:"Order review"}</p><h1>${editingOrder?"Update this order":"Review before submission"}</h1></div>${editingOrder?statusBadge("Editing Draft","warning"):statusBadge(draft.status,statusTone(draft.status))}</div>${editingOrder?`<div class="alert info"><span>i</span><p>This order already exists in ERPNext as a Draft. Saving here updates it in place - it stays a Draft until someone submits it in ERPNext. <button id="cancel-edit" class="text-action" type="button">Cancel edit</button></p></div>`:""}${customerSummary()}<section class="review-card"><div class="review-heading"><h2>Items</h2><button data-screen="order">+ Add more</button></div>${draft.items.length?draft.items.map(cartLineRow).join(""):emptyState("＋","No items yet","Return to the catalogue and add products.")}</section>${creditWarning?`<div class="alert warning"><span>!</span><p>Credit limit warning. ERPNext will apply the authoritative validation.</p></div>`:""}<section class="review-grid"><div class="review-card"><h2>Order details</h2><label>Delivery date<input id="delivery" type="date" value="${esc(draft.deliveryDate)}"></label><label>Customer PO<input id="po" value="${esc(draft.poNo)}" placeholder="Optional reference"></label><label>Notes<textarea id="remarks" rows="3" placeholder="Delivery or sales notes">${esc(draft.remarks)}</textarea></label></div><aside class="totals-card"><h2>Summary</h2><p><span>Displayed estimate</span><b>${money(total)}</b></p><p><span>ERPNext tax</span><b>${preview?money(tax):"Refresh required"}</b></p><p class="grand"><span>Grand total</span><strong>${preview?money(grand):money(total)}</strong></p><small>${preview?"Validated with ERPNext pricing.":"Refresh totals before final submission."}</small><button id="preview" class="secondary wide" ${submitting?"disabled":""}>↻ Refresh ERPNext total</button>${editingOrder?"":`<button id="save-draft" class="secondary wide" ${submitting?"disabled":""}>Save local draft</button>`}<button id="submit" class="primary wide" ${!draft.items.length||submitting?"disabled":""}>${submitting?(editingOrder?"Updating order…":"Creating order…"):(editingOrder?"Update Order":"Create Sales Order")}</button></aside></section></section>`
}
type HistoryRow={key:string;kind:"local"|"remote";label:string;sub:string;statusLabel:string;tone:UiTone;amount?:number;filterKey:string;time:number};
function buildHistoryRows():HistoryRow[]{
  const localRows:HistoryRow[]=loadDrafts().filter((entry)=>entry.status!=="submitted").map((entry)=>({
    key:`local:${entry.requestId}`,kind:"local",
    label:entry.customer||"Unassigned draft",
    sub:`${entry.items.length} line${entry.items.length===1?"":"s"} · Updated ${new Date(entry.updatedAt).toLocaleString()}`,
    statusLabel:entry.status==="draft"?"Saved on device":entry.status==="queued"?"Queued for sync":entry.status==="syncing"?"Syncing…":"Sync failed",
    tone:statusTone(entry.status),
    filterKey:entry.status==="syncing"?"queued":entry.status,
    time:new Date(entry.updatedAt).getTime()||0,
  }));
  const remoteRows:HistoryRow[]=history.map((row)=>({
    key:`remote:${text(row,"name")}`,kind:"remote",
    label:`${text(row,"name")} · ${text(row,"customer_name","customer")}`,
    sub:text(row,"transaction_date","creation"),
    statusLabel:text(row,"approval_status")==="Pending"?`Discount ${quantityText(row.requested_discount_percent)}% · pending approval`:text(row,"approval_status")==="Approved"?`Discount ${quantityText(row.requested_discount_percent)}% · approved`:text(row,"approval_status")==="Rejected"?`Discount rejected${text(row,"approval_comment")?` · ${text(row,"approval_comment")}`:""}`:text(row,"status")==="Draft"?"Draft in ERPNext":(text(row,"delivery_status","status")||"Draft"),
    tone:text(row,"approval_status")==="Approved"?"success":text(row,"approval_status")==="Rejected"?"danger":text(row,"approval_status")==="Pending"?"warning":statusTone(text(row,"status")),
    amount:Number(row.grand_total||0),
    filterKey:text(row,"status")||"Draft",
    time:new Date(String(row.modified||"").replace(" ","T")).getTime()||0,
  }));
  return [...localRows,...remoteRows].sort((a,b)=>b.time-a.time);
}
function myOrdersView(){
  const rows=buildHistoryRows();
  const visible=rows.filter((row)=>historyFilter==="All"||row.filterKey===historyFilter);
  const queued=rows.filter((row)=>row.filterKey==="queued").length;
  return `<section class="page"><div class="page-title"><div><p class="eyebrow">Pipeline</p><h1>My Orders</h1><p>Local drafts and ERPNext orders in one place.</p></div><button id="refresh-orders" class="secondary">↻ Refresh</button></div><div class="filter-tabs">${HISTORY_FILTERS.map(([key,label])=>`<button data-history-filter="${esc(key)}" ${key===historyFilter?'aria-selected="true"':""}>${esc(label)}</button>`).join("")}</div>${queued?`<div class="alert warning"><span>!</span><p>${queued} order${queued===1?"":"s"} queued for sync.</p><button id="sync" class="secondary" ${navigator.onLine&&!syncPromise?"":"disabled"}>${syncPromise?"Synchronizing…":"Sync now"}</button></div>`:""}<div class="history-list">${visible.map((row)=>`<article class="history-row ${row.kind}" aria-busy="${row.filterKey==="syncing"}"><div><strong>${esc(row.label)}</strong><small>${esc(row.sub)}</small></div>${statusBadge(row.statusLabel,row.tone)}${row.amount!=null?`<b>${money(row.amount)}</b>`:"<span></span>"}<div class="history-actions">${row.kind==="local"?`<button class="load secondary" data-id="${esc(row.key.slice(6))}" ${row.filterKey==="syncing"?"disabled":""}>Open</button>${row.filterKey==="failed"||row.filterKey==="queued"?`<button class="retry primary" data-id="${esc(row.key.slice(6))}" ${navigator.onLine&&!syncPromise?"":"disabled"}>Retry</button>`:""}`:(row.filterKey==="Draft"?`<button data-order-edit="${esc(row.key.slice(7))}">Edit →</button>`:`<button data-order-detail="${esc(row.key.slice(7))}">View →</button>`)}</div></article>`).join("")||emptyState("▣","Nothing here yet","Local drafts and ERPNext orders will appear here.")}</div></section>`
}
function managerApprovalPanel(){
  if(!isSalesManager()||!discountApprovals.length)return "";
  return `<section class="manager-approval-panel" aria-label="Pending discount approvals"><div class="manager-approval-head"><div><p class="eyebrow">Manager queue</p><h2>${discountApprovals.length} discount approval${discountApprovals.length===1?"":"s"}</h2></div><span>ERPNext enforced</span></div><div class="approval-card-grid">${discountApprovals.map((row)=>`<article class="approval-card"><div><strong>${esc(text(row,"sales_order"))}</strong><small>${esc(text(row,"customer_name","customer"))} · Requested by ${esc(text(row,"requested_by"))}</small></div><b>${quantityText(row.requested_percent)}%</b><p>${esc(text(row,"reason"))}</p><span>Order total ${formatMoney(row.grand_total,text(row,"currency")||currency())}</span><div><button class="secondary" data-reject-discount="${esc(text(row,"sales_order"))}">Reject</button><button class="primary" data-approve-discount="${esc(text(row,"sales_order"))}">Approve</button></div></article>`).join("")}</div></section>`
}
function profileView(){const queued=loadDrafts().filter((entry)=>entry.status==="queued").length;return `<section class="page"><div class="profile-card"><span class="profile-avatar">${esc(text(context,"full_name","user").slice(0,2).toUpperCase())}</span><div><p class="eyebrow">Sales profile</p><h1>${esc(text(context,"full_name","user"))}</h1><p>${esc(text(context,"territory")||"ERPNext Sales User")}</p></div>${statusBadge(navigator.onLine?"Online":"Offline",navigator.onLine?"success":"warning")}</div><div class="profile-grid"><section><h2>Workspace</h2><p><span>Company</span><b>${esc(text(context,"company")||"ERPNext default")}</b></p><p><span>Branch</span><b>${esc(draft.branch||"Not required")}</b></p><p><span>Warehouse</span><b>${esc(draft.warehouse||text(context,"warehouse"))}</b></p><p><span>Drafts on device</span><b>${loadDrafts().filter((entry)=>entry.status==="draft").length}</b></p><p><span>Queued for sync</span><b>${queued}</b></p><p><span>App version</span><b>v${esc(__APP_VERSION__)}</b></p></section><section><h2>Security & server</h2><p>Authentication and permissions are enforced by ERPNext. Prices, credit and stock are never client-authoritative.</p><p><span>Connected to</span><b>${esc(config?.baseUrl||"")}</b></p><button id="logout" class="secondary wide">Sign out securely</button><button id="change-server" class="secondary wide">Change ERPNext server</button></section></div></section>`}
function render(next:Screen=screen){
  if(next!=="order")cartOpen=false;
  screen=next;
  if(!context.user&&!context.full_name&&loading){root.innerHTML=`<section class="setup"><div class="setup-card">${loadingSkeleton(4)}<p>${esc(loading)}</p></div></section>`;return}
  // A full innerHTML rebuild replaces every DOM node, including whatever
  // input the user is actively typing in - on Android this drops focus and
  // can flicker the on-screen keyboard mid-keystroke (e.g. while typing a
  // customer search). Debounced searches re-render 300ms after each pause,
  // so this isn't rare. Capture focus/selection before the rebuild and
  // restore it on the new element with the same id afterward.
  const active=document.activeElement as (HTMLInputElement|HTMLTextAreaElement)|null;
  const focusId=active&&"id" in active?active.id:"";
  const selStart="selectionStart" in (active||{})?(active as HTMLInputElement).selectionStart:null;
  const selEnd="selectionEnd" in (active||{})?(active as HTMLInputElement).selectionEnd:null;
  const content=loading?`<section class="page">${loadingSkeleton(5)}<p class="loading-label">${esc(loading)}</p></section>`:screen==="customers"?customersView():screen==="order"?orderView():screen==="review"?reviewView():screen==="orders"?myOrdersView():profileView();
  root.innerHTML=`${header()}${syncBar()}${alert()}${screen==="order"||screen==="review"?deliveryPanel():""}${screen==="review"?discountPanel():""}${screen==="orders"?managerApprovalPanel():""}${content}${nav()}${confirmationPanel()}${screen==="order"?cartDrawer():""}`;bind();
  if(focusId){
    const restored=document.getElementById(focusId) as (HTMLInputElement|HTMLTextAreaElement)|null;
    if(restored){restored.focus({preventScroll:true});if(selStart!=null&&selEnd!=null&&"setSelectionRange" in restored){try{restored.setSelectionRange(selStart,selEnd)}catch{/* not all input types support range selection (e.g. type=date/number) */}}}
  }
}
function updateForm(){const discountInput=document.querySelector<HTMLInputElement>("#discount-percent");draft={...draft,branch:document.querySelector<HTMLSelectElement>("#branch")?.value??draft.branch,warehouse:document.querySelector<HTMLSelectElement>("#warehouse")?.value||draft.warehouse,deliveryDate:document.querySelector<HTMLInputElement>("#delivery")?.value||draft.deliveryDate,deliveryLocation:document.querySelector<HTMLSelectElement>("#delivery-location")?.value??draft.deliveryLocation,discountPercent:discountInput?Number(discountInput.value)||0:draft.discountPercent,discountReason:document.querySelector<HTMLTextAreaElement>("#discount-reason")?.value??draft.discountReason,poNo:document.querySelector<HTMLInputElement>("#po")?.value||draft.poNo,remarks:document.querySelector<HTMLTextAreaElement>("#remarks")?.value||draft.remarks};save(draft)}
function addProduct(code:string,delta=1){const product=itemIndex.get(code)||products.find((entry)=>text(entry,"name","item_code")===code);if(!product)return;const old=draft.items.find((entry)=>entry.item_code===code),selected=selectedUoms.get(code);const uom=old?.uom||(itemUoms(product).some((entry)=>text(entry,"uom")===selected)?selected:defaultItemUom(product));draft=setDraftItem(draft,{item_code:code,qty:(old?.qty||0)+delta,uom});save(draft);preview=null;remember(recentItemsKey,code);notice(delta>0?`${text(product,"item_name","name")} added`:"Quantity updated","success");render(screen)}
function setProductQuantity(code:string,qty:number){const product=itemIndex.get(code)||products.find((entry)=>text(entry,"name","item_code")===code);if(!product||!Number.isFinite(qty)||qty<0)return;const old=draft.items.find((entry)=>entry.item_code===code),selected=selectedUoms.get(code);const uom=old?.uom||(itemUoms(product).some((entry)=>text(entry,"uom")===selected)?selected:defaultItemUom(product));draft=setDraftItem(draft,{item_code:code,qty,uom});save(draft);preview=null;if(qty>0)remember(recentItemsKey,code);render(screen)}
async function loadOrders(){loading="Loading server orders";render();try{const [ordersResult,approvalsResult]=await Promise.all([api!.getOrders().then(payload),isSalesManager()?api!.getDiscountApprovals("Pending",50).then(payload):Promise.resolve({approvals:[]} as Row)]);history=list(ordersResult.orders);discountApprovals=list(approvalsResult.approvals);notice(discountApprovals.length?`${history.length} orders · ${discountApprovals.length} discount approval${discountApprovals.length===1?"":"s"} waiting`:`${history.length} orders loaded`,discountApprovals.length?"warning":"success")}catch(error){notice(error instanceof Error?error.message:"Unable to load orders","danger")}finally{loading="";render("orders")}}
async function decideDiscount(orderName:string,approved:boolean){const comment=prompt(approved?"Approval comment (optional)":"Why is this discount rejected?")??"";if(!approved&&!comment.trim()){notice("A rejection comment is required.","warning");return render("orders")}loading=approved?"Approving discount":"Rejecting discount";render();try{await payload(await api!.approveDiscount(orderName,approved,comment));notice(`${orderName} discount ${approved?"approved":"rejected"}.`,approved?"success":"warning");await loadOrders()}catch(error){notice(error instanceof Error?error.message:"Unable to decide discount","danger");loading="";render("orders")}}
